    <text x="20" y="28" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">ETH/BTC Bounce vs Dominance vs Altcoin Season Index — Portrait of a Narrow Rotation</text>
    <g font-family="sans-serif">
      <text x="20" y="55" fill="#a1a1aa" font-size="13" font-weight="700">① ETH/BTC Ratio (Past Month)</text>
      <line x1="60" y1="105" x2="640" y2="105" stroke="rgba(255,255,255,.2)" stroke-width="1.5"/>
      <circle cx="90" cy="105" r="6" fill="#71717a"/>
      <text x="90" y="128" fill="#71717a" font-size="13" text-anchor="middle">1 Month Ago</text>
      <text x="90" y="90" fill="#a1a1aa" font-size="13" text-anchor="middle">0.0255</text>
